mapper.select:
select t1.*, t2.username as `reporter_name`, t3.context as `reason` from `report` as t1 left join `user` as t2
on t1.reporter_id = t2.id left join `report_reason` as t3 on t1.reason_id = t3.id


        and t2.username like concat('%', #{reporter}, '%')


        and t1.reason_id = #{reasonId}


        and t1.target_type = #{targetType}


        and t1.status = #{status}
